对n行n列（n&lt;10）二维数组的每一行排序，偶数行(0当作偶数)由小到大排序，奇数行由大到小排序。【含有错误的源程序】
#include &lt;stdio.h&gt; 
#define N=4
void swap(int *p1, int *p2)
{
    int p;
    p=p1; p1=p2; p2=p;
}
void sort(int a[N][N])
{
    int i,j,k;
    for(i=0; i&lt;N; i++)
        for(j=0; j&lt;N; j++)
            for(k=j+1; k&lt;N; k++)
                if(i%2=0)
                {
                    if(a[i][j]&gt;a[i][k])
                        swap(a[i]+j,a[i]+k);
                }
                else
                {
                    if(a[i][j]&lt;a[i][k])
                        swap(a[i]+j,a[i]+k);
                }
}
int main()
{
    int a[N][N];
    for(i=0; i&lt;N; i++)
        for(j=0; j&lt;N; j++)
            scanf(&quot;%d&quot;, &amp;a[i][j]);
    sort(a[N][N]);
    int i,j;
    for(i=0; i&lt;N; i++)
    {
        for(j=0; j&lt;N; j++)
            printf(&quot;%5d&quot;, a[i][j]);
        printf(&quot;\n&quot;); 
    }
    return 0;
}

输入2个正确日期且年份在1900-9999范围内，计算并输出2个日期之间间隔的天数。例如：2008-8-1和2009-8-1之间间隔的天数为365。
提示：能被4整除并且不能被100整除或者能被400整除的年份是闰年，其他年份是平年。
【含有错误的源程序】
#include &lt;stdio.h&gt;
#define leap(int y) ((y)%4==0 &amp;&amp; (y)%100!=0 || (y)%400==0)
struct d
{  int y,m,d;  };
int days(struct d d1,struct d d2)
{
    int mon[2][13]={{0,31,28,31,30,31,30,31,31,30,31,30,31},
                    {0,31,29,31,30,31,30,31,31,30,31,30,31}};
    int i, td=0;
    for(i=d1.y; i&lt;d2.y; i++)
        td=leap(i)?366:365;
    for(i=1; i&lt;d1.m; i++)
        td-=mon[leap(d1.y)][i];
    td-=d1.d-1;
    for(i=1;i&lt;d2.m;i++)
        td+=mon[leap(d2.y)][i];
    td+=d2.d-1;
    return td;
}
int  main()
{
    struct    d1,d2;
    scanf(&quot;%d-%d-%d&quot;, &amp;d1.y,&amp;d1.m,&amp;d1.d);
    scanf(&quot;%d-%d-%d&quot;, &amp;d2.y,&amp;d2.m,&amp;d2.d);
    printf(&quot;%d days&quot;,days(d1.y,d2.y));
    return 0; 
}
